    {'id':"y5-t3-w4-l1",'year':"Y5",'term':"T3",     'week':4,'weekLesson':1,     'sequence':"Mastery 2",'lesson':"Lesson 1",     'focus':"the ough letter string",     'explanation':"The 'ough' quadgraph (four-letter grapheme) represents several different sounds including /uff/ (tough, rough, enough) and /off/ (cough, trough); because no single phonics rule governs it, these words must be learned by sight and memory.",     'hlWords':["tough", "rough", "enough", "cough", "trough", "although", "through", "thought", "bought", "drought"]},
    {'id':"y5-t3-w4-l2",'year':"Y5",'term':"T3",     'week':4,'weekLesson':2,     'sequence':"Mastery 2",'lesson':"Lesson 2",     'focus':"the ough letter string",     'explanation':"In this lesson the 'ough' quadgraph represents the sounds /oa/ (dough), /oo/ (through), /uh/ (thorough), and /ow/ (plough, bough); these longer vowel-like sounds are particularly tricky because simpler phonetic spellings such as 'oa' or 'oo' would seem more predictable.",     'hlWords':["dough", "through", "thorough", "plough", "drought", "borough", "bough", "although", "furlough", "sourdough"]},
