    {'id':"y5-t4-w1-l1",'year':"Y5",'term':"T4",     'week':1,'weekLesson':1,     'sequence':"Sequence 5",'lesson':"Lesson 1",     'focus':"silent letters",     'explanation':"The silent letter k precedes n at the start of a word (know, knife), g precedes n (gnat, gnome), w precedes r (wrap, wrong), and h follows w at the start of a word (where, white) — in all these cases one letter in the pair is written but not pronounced.",     'hlWords':["gnat", "gnome", "gnaw", "wrap", "wrong", "written", "where", "white", "know", "knife"]},
