    {'id':"y5-t4-w4-l1",'year':"Y5",'term':"T4",     'week':4,'weekLesson':1,     'sequence':"Sequence 6",'lesson':"Lesson 1",     'focus':"ei after c",     'explanation':"When the long 'ee' sound follows the letter c, the spelling is ei (receive, ceiling, deceive, receipt); in most other positions ie is used (believe, shield, achieve) — the mnemonic 'i before e except after c' supports pupils' recall of this rule.",     'hlWords':["receive", "ceiling", "perceive", "receipt", "deceive", "believe", "shield", "achieve", "conceit", "retrieve"]},
