    {'id':"y6-t2-w3-l3",'year':"Y6",'term':"T2",     'week':3,'weekLesson':3,     'sequence':"Sequence 2",'lesson':"Lesson 9",     'focus':"words ending in -ible/-able",     'explanation':"Pupils form adverbs using -ibly and -ably: -ably attaches to -able adjectives (notably, reasonably, noticeably) while -ibly attaches to -ible adjectives (possibly, incredibly); the same suffix rules govern both the adjective and adverb forms.",     'hlWords':["notably", "reasonably", "adorably", "possibly", "noticeably", "incredibly", "considerably", "comfortably", "tolerably", "visibly"]},
    {'id':"y6-t2-w4-l1",'year':"Y6",'term':"T2",     'week':4,'weekLesson':1,     'sequence':"Sequence 3",'lesson':"Lesson 1",     'focus':"hyphenated words",     'explanation':"A hyphen is required when a prefix ends with the same vowel that begins the root word (e.g. re-enter, re-elect, co-own, pre-existing) to prevent double letters that would look like a different word or be confusing to read.",     'hlWords':["re-enter", "re-elect", "re-educate", "re-enact", "re-evaluate", "co-own", "re-examine", "co-owner", "pre-existing", "re-open"]},
